import{_ as t,o as i,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"iOS SDK Overview","description":"","frontmatter":{"title":"iOS SDK Overview","slug":"ios-sdk-overview"},"headers":[],"relativePath":"developer-hub/ios-sdk-overview.md","filePath":"developer-hub/ios-sdk-overview.md"}'),n={name:"developer-hub/ios-sdk-overview.md"};function o(s,e,l,h,p,d){return i(),a("div",null,[...e[0]||(e[0]=[r('<h3 id="sdk-stats" tabindex="-1">SDK Stats <a class="header-anchor" href="#sdk-stats" aria-label="Permalink to &quot;SDK Stats&quot;">​</a></h3><p><strong>Open Source Github Repo</strong>: <a href="https://github.com/BranchMetrics/ios-branch-deep-linking" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/ios-branch-deep-linking</a></p><p><strong>SDK Size</strong>: ~220kb (with all Branch features enabled)</p><p><strong>Speed</strong>: Median 80ms to 250ms</p><p><strong>Minimum XCode Version</strong>: 15.0+</p><p><strong>Minimum OS version</strong>: iOS 12+</p><h3 id="ios-demo-app" tabindex="-1">iOS Demo App <a class="header-anchor" href="#ios-demo-app" aria-label="Permalink to &quot;iOS Demo App&quot;">​</a></h3><p><strong>Want to take our technology for a test drive before implementing it?</strong></p><p><a href="https://apps.apple.com/us/app/branch-monster-factory/id917737838" target="_blank" rel="noreferrer">DOWNLOAD BRANCH MONSTER FACTORY</a></p><p><strong>Want to dive into the code directly?</strong></p><p><a href="https://github.com/BranchMetrics/Branch-Example-Deep-Linking-Branchster-iOS" target="_blank" rel="noreferrer">VIEW BRANCH MONSTER FACTORY GITHUB</a></p><h3 id="basic-integration" tabindex="-1">Basic Integration <a class="header-anchor" href="#basic-integration" aria-label="Permalink to &quot;Basic Integration&quot;">​</a></h3><p><strong>Integrating the Branch iOS SDK is required for the following features:</strong></p><ul><li>Ads</li><li>Email</li><li>Journeys</li></ul><p><a href="./ios-basic-integration.html">INTEGRATE THE BRANCH SDK</a></p><h3 id="advanced-features" tabindex="-1">Advanced Features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced Features&quot;">​</a></h3><p><strong>After completing the basic integration, you can implement the following features:</strong></p><ul><li>Create content reference</li><li>Create deep link</li><li>Share deep link</li><li>Read deep link</li><li>Navigate to content</li><li>Display content</li><li>Track content</li><li>Handle push notifications</li><li>Handle links in your own app</li></ul><p><a href="./ios-advanced-features.html">IMPLEMENT ADVANCED FEATURES</a></p><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><p><strong>Test your Branch integration before your app goes live.</strong></p><p><a href="./ios-testing.html">TEST THE INTEGRATION</a></p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><p><strong>Running into issues? Browse our troubleshooting section to find a solution.</strong></p><p><a href="./ios-troubleshooting.html">SEARCH SOLUTIONS</a></p><h3 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to &quot;Version History&quot;">​</a></h3><p><strong>View past versions of the Branch SDK for iOS including changes.</strong></p><p><a href="./ios-version-history.html">VIEW VERSION HISTORY</a></p><h3 id="full-reference" tabindex="-1">Full Reference <a class="header-anchor" href="#full-reference" aria-label="Permalink to &quot;Full Reference&quot;">​</a></h3><p><strong>The information presented here serves as a reference manual for our iOS SDK.</strong></p><p><a href="./ios-full-reference.html">VIEW FULL REFERENCE</a></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Why is iOS Redirect not working when I have Universal Links enabled?</summary><p>Taking into understanding that your app&#39;s Branch SDK integration is set up just fine and Universal Links are enabled, this seems to be an issue where the AASA files are not getting downloaded in the device.</p><p>There is a known universal bug for Apple where devices for iOS version 11.x+ , the AASA files do not get fetched and thus causing the Universal Links to fail.</p><p>To troubleshoot, try the following:</p><ol><li><p>Follow the steps outlined in this guide to <a href="https://help.branch.io/developers-hub/docs/ios-troubleshooting" target="_blank" rel="noreferrer">validate if your AASA file successfully downloaded</a>.</p></li><li><p>If the issue persists, check on the following:</p><ol><li><p>Uninstall the app from the device</p></li><li><p>Restart the device</p></li><li><p>Reinstall app</p><p><em>It may take 2-3 tries for this to work. Normally, the Apple OS looks into retrying to fetch the AASA file at some time interval but the workaround might help for a test condition.</em></p></li></ol></li><li><p>Inside the app, check if the AASA files were downloaded successfully or not. To do this:</p><ol><li>Copy the link into your notes app.</li><li>Long-press the link till a dropdown appears. If the dropdown shows &#39;Open link&#39;, then Universal Links are not working for that device. If the link shows &#39;Open in app name&#39;, the configuration is working fine.</li></ol></li></ol></details><details><summary>Why are email deep links working on Android but not on iOS?</summary><p>Branch deep links in emails do not work for iOS, since Branch uses Universal Links property to launch the app. As the Universal Links work on link domains, the mailer links wrap the Branch link into a click tracking domain, and hence the final URL changes. When you click the mailer link, it redirects to Branch link on the web as the Universal Links will not work with the new domain.</p><p>For such use cases, we have <a href="https://help.branch.io/v1/docs/branch-universal-email" target="_blank" rel="noreferrer">Branch Email</a> where we have partnered with different <a href="https://help.branch.io/v1/docs/email-partners-list" target="_blank" rel="noreferrer">Email Service Providers (ESPs)</a> to support direct app open, deep linking and attribution.</p></details><details><summary>What is the minimum SDK version required to get ATT opt-in and opt-out data?</summary><p>iOS SDK Version 1.39.1 and above is required.</p></details><details><summary>When is the AASA file fetched once I update the AASA file?</summary><p>Usually, the apple-app-site-association file is checked when the app is first installed and then rechecked during any later app updates from the App Store. So if you add an additional path to the file, it would be detected when the next update app is released but likely not before. Updating the app will usually re-cache the AASA file.</p></details>',36)])])}const f=t(n,[["render",o]]);export{u as __pageData,f as default};
